import React from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const StudyRoom = ({ dayData }) => {
  const navigate = useNavigate();

  const handleFinishDay = async (completed) => {
    try {
      if (completed) {
        await axios.put(`/api/days/${dayData._id}`, { 
          status: 'completed' 
        });
      } else {
        await axios.post('/api/days/reschedule', { 
          dayId: dayData._id,
          originalDate: dayData.date 
        });
      }
      navigate('/planPage');
    } catch (error) {
      console.error("Update failed", error);
    }
  };

  return (
    <div className="study-room">
      <h1>{dayData.title}</h1>
      <button onClick={() => handleFinishDay(true)}>
        Finish Day (Completed)
      </button>
      <button onClick={() => handleFinishDay(false)}>
        Not Finished (Reschedule)
      </button>
    </div>
  );
};

export default StudyRoom;
